// Dữ liệu trắc nghiệm Chương 3 (Câu 229 - 357)
const QUESTIONS_C3 = [
  {"id": 229, "chapter": "CHƯƠNG 3", "question": "Câu 1. Tại kỳ họp đầu tiên (6/1976) của Quốc hội nước Việt Nam thống nhất đã quyết định vấn đề quan trọng gì?", "options": ["A. Đặt tên nước là Cộng hòa xã hội chủ nghĩa Việt Nam", "B. Cải cách ruộng đất trong cả nước", "C. Thành lập Mặt trận Việt Nam độc lập đồng minh", "D. Tiến hành đổi mới toàn diện đất nước"], "answer": 0, "explanation": "Quốc hội khóa VI quyết định đặt tên nước là Cộng hòa xã hội chủ nghĩa Việt Nam (Trang 100)."},
  {"id": 230, "chapter": "CHƯƠNG 3", "question": "Câu 2. Việt Nam thực hiện thống nhất đất nước về mặt nhà nước ngay sau đại thắng mùa xuân năm 1975 vì:", "options": ["A. Đó là ý chí và nguyện vọng thiết tha của toàn dân tộc", "B. Muốn tạo sức mạnh tổng hợp để tham gia xu thế toàn cầu hóa", "C. Đó là một điều khoản phải thi hành của Hiệp định Paris năm 1973", "D. Phải hoàn thành triệt để cuộc cách mạng giải phóng dân tộc"], "answer": 0, "explanation": "Thống nhất đất nước về mặt nhà nước phản ánh nguyện vọng cháy bỏng của nhân dân cả nước (Trang 100)."},
  {"id": 231, "chapter": "CHƯƠNG 3", "question": "Câu 3. Nội dung nào dưới đây là điều kiện thuận lợi của Việt Nam ngay sau đại thắng mùa Xuân 1975?", "options": ["A. Đất nước đã thống nhất về mặt lãnh thổ", "B. Hậu quả chiến tranh đã khắc phục xong", "C. Mỹ đã bình thường hóa quan hệ với Việt Nam", "D. Nền kinh tế bước đầu có tích lũy nội bộ"], "options": ["A. Đất nước đã thống nhất về mặt lãnh thổ", "B. Hậu quả chiến tranh đã khắc phục xong", "C. Mỹ đã bình thường hóa quan hệ với Việt Nam", "D. Nền kinh tế bước đầu có tích lũy nội bộ"], "answer": 0, "explanation": "Thuận lợi căn bản nhất là đất nước đã thu về một mối, thống nhất hoàn toàn về mặt lãnh thổ (Trang 100)."},
  {"id": 232, "chapter": "CHƯƠNG 3", "question": "Câu 4. Hoàn cảnh lịch sử Việt Nam sau ngày 30/4/1975?", "options": ["A. Đất nước hòa bình, độc lập", "B. Đất nước thống nhất", "C. Cả nước quá độ lên chủ nghĩa xã hội", "D. Tất cả các đáp án trên"], "answer": 3, "explanation": "Đất nước bước ra khỏi chiến tranh trong hòa bình, độc lập, thống nhất và cả nước bước vào thời kỳ quá độ (Trang 100)."},
  {"id": 233, "chapter": "CHƯƠNG 3", "question": "Câu 5. Sau đại thắng mùa xuân năm 1975, Đảng Cộng sản Việt Nam xác định nhiệm vụ đầu tiên, bức thiết nhất lúc này cần phải làm là gì?", "options": ["A. Xây dựng kinh tế", "B. Thống nhất nước nhà về mặt nhà nước", "C. Phát triển văn hóa – xã hội", "D. Củng cố quốc phòng – an ninh"], "answer": 1, "explanation": "Nhiệm vụ đầu tiên và cấp thiết nhất là hoàn thành thống nhất đất nước về mặt Nhà nước (Trang 100)."},
  {"id": 234, "chapter": "CHƯƠNG 3", "question": "Câu 6. Khó khăn cơ bản nhất của Việt Nam sau năm 1975 là gì?", "options": ["A. Mù chữ và thất nghiệp chiếm tỷ lệ cao", "B. Phản động trong nước vẫn còn", "C. Nông nghiệp lạc hậu", "D. Hậu quả nặng nề của chiến tranh"], "answer": 3, "explanation": "Hậu quả phá hoại cực kỳ nặng nề của chiến tranh kéo dài 30 năm là khó khăn lớn nhất của đất nước (Trang 100)."},
  {"id": 235, "chapter": "CHƯƠNG 3", "question": "Câu 7. Nhiệm vụ trọng tâm của miền Bắc ngay sau năm 1975 là?", "options": ["A. Hàn gắn vết thương chiến tranh", "B. Khắc phục hậu quả chiến tranh, khôi phục và phát triển kinh tế, văn hóa", "C. Tiếp tục làm nhiệm vụ căn cứ địa của cách mạng cả nước", "D. Tiếp tục làm nghĩa vụ quốc tế với Lào và Campuchia"], "answer": 1, "explanation": "Trọng tâm của miền Bắc là khắc phục hậu quả chiến tranh, khôi phục phát triển kinh tế để chi viện cho cả nước (Trang 100)."},
  {"id": 236, "chapter": "CHƯƠNG 3", "question": "Câu 8. Ngày 25/4/1976 ở Việt Nam diễn ra sự kiện quan trọng gì?", "options": ["A. Tổng tuyển cử trên toàn lãnh thổ miền Nam", "B. Bầu Quốc hội chung của cả nước", "C. Tổng tuyển cử trên toàn lãnh thổ Việt Nam, bầu Quốc hội chung của cả nước", "D. Ban hành Hiến pháp"], "answer": 2, "explanation": "Ngày 25/4/1976, cử tri cả nước hăng hái đi bầu cử Quốc hội khóa VI chung cho cả nước thống nhất (Trang 100)."},
  {"id": 237, "chapter": "CHƯƠNG 3", "question": "Câu 9. Cuộc Tổng tuyển cử bầu Quốc hội chung trong cả nước (25/4/1976) có ý nghĩa như thế nào đối với nước ta?", "options": ["A. Lần thứ 2 cuộc tổng tuyển cử được tổ chức trong cả nước", "B. Kết quả thắng lợi của 30 năm chiến tranh giữ nước (1945-1975)", "C. Là một bước quan trọng cho sự thống nhất đất nước về mặt Nhà nước", "D. Tất cả các đáp án trên"], "answer": 2, "explanation": "Tổng tuyển cử thắng lợi là mốc lịch sử quan trọng trong quá trình thống nhất đất nước về mặt nhà nước (Trang 100)."},
  {"id": 240, "chapter": "CHƯƠNG 3", "question": "Câu 10. Thành phố Sài Gòn được Quốc hội đặt tên là Thành phố Hồ Chí Minh từ năm nào?", "options": ["A. Năm 1974", "B. Năm 1975", "C. Năm 1976", "D. Năm 1977"], "answer": 2, "explanation": "Tại kỳ họp đầu tiên của Quốc hội thống nhất năm 1976, Sài Gòn được đổi tên thành TP. Hồ Chí Minh (Trang 100)."},
  {"id": 241, "chapter": "CHƯƠNG 3", "question": "Câu 11. Tại kỳ họp thứ nhất của Quốc hội nước Việt Nam thống nhất đã có những quyết định quan trọng nào liên quan với việc thống nhất đất nước về mặt Nhà nước?", "options": ["A. Thống nhất tên nước, xác định Hà Nội là thủ đô của cả nước", "B. Bầu các cơ quan lãnh đạo cao nhất của cả nước", "C. Đổi tên thành phố Sài Gòn – Gia Định là Thành phố Hồ Chí Minh", "D. Thống nhất tên nước, xác định Hà Nội là thủ đô của cả nước và bầu các chức danh lãnh đạo cấp cao của Nhà nước"], "answer": 3, "explanation": "Quốc hội đã thảo luận và thông qua các quyết định về tên nước, thủ đô, quốc ca, quốc huy và bầu bộ máy lãnh đạo mới (Trang 100)."},
  {"id": 242, "chapter": "CHƯƠNG 3", "question": "Câu 12. Người được bầu làm Chủ tịch đầu tiên của nước Cộng hòa xã hội chủ nghĩa Việt Nam là ai?", "options": ["A. Hồ Chí Minh", "B. Tôn Đức Thắng", "C. Nguyễn Lương Bằng", "D. Trần Đức Lương"], "answer": 1, "explanation": "Cụ Tôn Đức Thắng vinh dự được Quốc hội khóa VI bầu làm Chủ tịch nước đầu tiên của Việt Nam thống nhất (Trang 100)."},
  {"id": 243, "chapter": "CHƯƠNG 3", "question": "Câu 13. Đại hội đại biểu toàn quốc lần thứ IV của Đảng được họp vào thời gian nào?", "options": ["A. Tháng 5/1974", "B. Tháng 10/1975", "C. Tháng 12/1976", "D. Tháng 12/1986"], "answer": 2, "explanation": "Đại hội đại biểu toàn quốc lần thứ IV họp từ ngày 14 đến 20/12/1976 tại Hà Nội (Trang 101)."},
  {"id": 244, "chapter": "CHƯƠNG 3", "question": "Câu 14. Đại hội lần thứ IV của Đảng (1976) đã nêu ra đặc điểm nổi bật của cách mạng Việt Nam trong giai đoạn mới là?", "options": ["A. Nước ta đang trong quá trình phát triển kinh tế một cách bền vững, đa nghề", "B. Nước ta đang trong quá trình hoàn thành giai đoạn quá độ, chuẩn bị tiến lên chủ nghĩa xã hội", "C. Nước ta đã hoàn thành giai đoạn xây dựng chủ nghĩa xã hội, chuẩn bị tiến lên chủ nghĩa cộng sản", "D. Nước ta đang trong quá trình từ sản xuất nhỏ tiến thẳng lên chủ nghĩa xã hội, bỏ qua giai đoạn phát triển tư bản chủ nghĩa"], "answer": 3, "explanation": "Đại hội IV chỉ rõ nước ta đang đi từ sản xuất nhỏ tiến thẳng lên CNXH, bỏ qua tư bản chủ nghĩa (Trang 101)."},
  {"id": 245, "chapter": "CHƯƠNG 3", "question": "Câu 15. Nội dung nào không phản ánh đúng quyết định của Đại hội toàn quốc lần thứ IV của Đảng (1976)?", "options": ["A. Đổi tên Đảng Lao động Việt Nam thành Đảng Cộng sản Việt Nam", "B. Đề ra đường lối xây dựng chủ nghĩa xã hội trong cả nước", "C. Đề ra kế hoạch phát triển kinh tế và văn hóa (1976-1980)", "D. Thực hiện đường lối đổi mới toàn diện đất nước đi lên chủ nghĩa xã hội"], "answer": 3, "explanation": "Đường lối đổi mới toàn diện được thông qua tại Đại hội VI năm 1986, không phải Đại hội IV (Trang 101)."},
  {"id": 246, "chapter": "CHƯƠNG 3", "question": "Câu 16. Trong giai đoạn 10 năm (1976-1986) Việt Nam vừa xây dựng chủ nghĩa xã hội vừa thực hiện những cuộc đấu tranh nào?", "options": ["A. Bảo vệ Tổ quốc ở biên giới Đông Nam và Tây Nam", "B. Bảo vệ Tổ quốc ở biên giới phía Bắc và Tây Nam", "C. Chống lại sự xâm nhập của tập đoàn Khơme Đỏ ở phía Bắc", "D. Chống lại sự tấn công của Trung Quốc ở phía Tây Nam"], "answer": 1, "explanation": "Giai đoạn 1976-1986, Việt Nam phải thực hiện hai cuộc chiến đấu bảo vệ biên giới Tây Nam và biên giới phía Bắc (Trang 103)."},
  {"id": 247, "chapter": "CHƯƠNG 3", "question": "Câu 17. Theo Hiệp ước Hòa bình, hữu nghị và hợp tác giữa Việt Nam và Campuchia (18/2/1979), quân đội Việt Nam có mặt ở Campuchia giúp bạn bảo vệ độc lập và hồi sinh đất nước. Hành động đó được coi là?", "options": ["A. Hành động xâm lược Campuchia", "B. Hành động chống phá nước bạn", "C. Hành động chính nghĩa và xuất phát từ nhu cầu tự vệ chính đáng của nước bạn", "D. Hành động nhằm tàn sát, phá hoại nước bạn"], "answer": 2, "explanation": "Sự hiện diện của quân tình nguyện Việt Nam là hành động chính nghĩa giúp cứu nhân dân Campuchia khỏi nạn diệt chủng (Trang 104)."},
  {"id": 248, "chapter": "CHƯƠNG 3", "question": "Câu 18. Nội dung nào sau đây không phải là hành động của Trung Quốc trong quan hệ ngoại giao với Việt Nam vào cuối năm 1978 đầu năm 1979?", "options": ["A. Cho quân khiêu khích dọc biên giới phía Bắc của Việt Nam", "B. Dựng lên sự kiện \"nạn kiều\"", "C. Cắt viện trợ, rút hết các chuyên gia về nước", "D. Giúp đỡ Việt Nam trong cuộc đấu tranh bảo vệ biên giới Tây Nam"], "answer": 3, "explanation": "Trung Quốc không giúp đỡ Việt Nam bảo vệ biên giới Tây Nam mà ngược lại còn có các hành động leo thang căng thẳng (Trang 104)."},
  {"id": 249, "chapter": "CHƯƠNG 3", "question": "Câu 19. Thắng lợi của cuộc chiến đấu bảo vệ biên giới phía Bắc (1979) có ý nghĩa như thế nào đối với Việt Nam?", "options": ["A. Tạo ra bước ngoặt để cả nước tiến hành đổi mới toàn diện đất nước", "B. Bảo vệ vững chắc vùng biên giới phía Bắc của nhân dân ta", "C. Hoàn thành cuộc cách mạng xã hội chủ nghĩa trên cả nước", "D. Đưa đất nước vào thời kỳ bình ổn, tăng trưởng nhanh về kinh tế"], "answer": 1, "explanation": "Cuộc chiến đấu kiên cường bảo vệ vững chắc biên cương phía Bắc của Tổ quốc (Trang 104)."},
  {"id": 250, "chapter": "CHƯƠNG 3", "question": "Câu 20. Bước đột phá đầu tiên trong đổi mới kinh tế của Đảng với chủ trương phá bỏ những rào cản để cho \"sản xuất bung ra\" được đề ra tại Hội nghị Trung ương nào?", "options": ["A. Hội nghị Trung ương 6 (1979)", "B. Hội nghị Trung ương 6 (1984)", "C. Hội nghị Trung ương 6 (1989)", "D. Hội nghị Trung ương 6 (1994)"], "answer": 0, "explanation": "Nghị quyết Hội nghị Trung ương 6 (8/1979) mở đường cho việc tháo gỡ rào cản, cho sản xuất nông - công nghiệp bung ra (Trang 105)."},
  {"id": 251, "chapter": "CHƯƠNG 3", "question": "Câu 21. Chỉ thị 100 CT/TW của Ban Bí thư Trung ương Đảng (1/1981) đã đưa ra chủ trương nào sau đây?", "options": ["A. Khoán sản phẩm đến nhóm và người lao động trong hợp tác xã nông nghiệp", "B. Cải cách ruộng đất", "C. Đổi mới toàn diện đất nước", "D. Tất cả các đáp án trên"], "answer": 0, "explanation": "Chỉ thị 100 (Khoán 100) đưa ra chủ trương khoán sản phẩm đến nhóm và người lao động trong HTX nông nghiệp (Trang 105)."},
  {"id": 252, "chapter": "CHƯƠNG 3", "question": "Câu 22. Chiến thắng chiến tranh biên giới Tây Nam (1978) của quân dân ta có ý nghĩa như thế nào?", "options": ["A. Tạo thời cơ thuận lợi cho cách mạng Campuchia giành thắng lợi", "B. Tăng cường tính đoàn kết của nhân dân 3 nước Đông Dương", "C. Tạo nên sức mạnh tổng hợp của nhân dân hai nước Việt Nam và Campuchia", "D. Đánh vào âm mưu chống phá của quân Trung Quốc"], "answer": 0, "explanation": "Đập tan đòn xâm lược biên giới Tây Nam của Pôn Pốt, tạo cơ hội cho lực lượng cách mạng Campuchia lật đổ chế độ diệt chủng (Trang 104)."},
  {"id": 253, "chapter": "CHƯƠNG 3", "question": "Câu 23. Chỉ thị 100 CT/TW của Ban Bí thư Trung ương Đảng về khoán sản phẩm đến nhóm và người lao động trong hợp tác xã được ban hành vào năm nào?", "options": ["A. 1980", "B. 1981", "C. 1988", "D. 1989"], "answer": 1, "explanation": "Chỉ thị 100 được Ban Bí thư ban hành vào tháng 1/1981 (Trang 105)."},
  {"id": 254, "chapter": "CHƯƠNG 3", "question": "Câu 24. Những khó khăn, thách thức mới trong công cuộc xây dựng chủ nghĩa xã hội và bảo vệ Tổ quốc 1976-1981 là gì?", "options": ["A. Tiến hành công nghiệp hóa, hiện đại hóa trên phạm vi miền Bắc", "B. Tiến hành công nghiệp hóa, hiện đại hóa trên phạm vi cả nước", "C. Các thế lực thù địch bao vây cấm vận và phá hoại sự phát triển của Việt Nam", "D. Tất cả các đáp án trên"], "answer": 2, "explanation": "Thách thức lớn là các thế lực thù địch bao vây cấm vận kinh tế và hoạt động chống phá nhiều mặt (Trang 103)."},
  {"id": 255, "chapter": "CHƯƠNG 3", "question": "Câu 25. Giai đoạn 1976-1981, quân và dân cả nước đã giành được những thành tựu nổi bật nào?", "options": ["A. Hoàn thành thống nhất đất nước về mặt nhà nước", "B. Chiến thắng trong hai cuộc chiến tranh biên giới", "C. Đã khắc phục được một phần hậu quả chiến tranh và thiên tai", "D. Tất cả các đáp án trên"], "answer": 3, "explanation": "Thời kỳ này ta đạt thành tựu thống nhất non sông, bảo vệ Tổ quốc ở biên giới và khôi phục kinh tế từng bước (Trang 103/104)."},
  {"id": 256, "chapter": "CHƯƠNG 3", "question": "Câu 26. Những khó khăn, thách thức của Việt Nam trong giai đoạn 1975-1981 là do?", "options": ["A. Do chiến tranh kéo dài", "B. Do tiến hành quá lâu nền kinh tế kế hoạch hóa tập trung quan liêu bao cấp", "C. Do Mỹ bao vây, cô lập và cấm vận kinh tế Việt Nam", "D. Tất cả các đáp án trên"], "answer": 3, "explanation": "Do đồng loạt nhiều nguyên nhân: chiến tranh kéo dài, cơ chế bao cấp lỗi thời và sự bao vây cấm vận của phương Tây (Trang 105)."},
  {"id": 257, "chapter": "CHƯƠNG 3", "question": "Câu 27. Đại hội đại biểu toàn quốc lần thứ V của Đảng (1982) đã họp trong hoàn cảnh thế giới và trong nước có những khó khăn, thách thức gì?", "options": ["A. Hoa Kỳ tiếp tục thực hiện chính sách bao vây cấm vận và \"kế hoạch hậu chiến\"", "B. Chủ nghĩa đế quốc và các thế lực phản động quốc tế ra sức tuyên truyền xuyên tạc việc quân tình nguyện Việt Nam làm nghĩa vụ quốc tế ở Campuchia", "C. Trong nước tình trạng khủng hoảng kinh tế – xã hội ở nước ta ngày càng trầm trọng", "D. Tất cả các đáp án trên"], "answer": 3, "explanation": "Đại hội V diễn ra giữa bối cảnh trong nước khủng hoảng kinh tế nghiêm trọng, quốc tế bao vây cô lập ác liệt (Trang 106)."},
  {"id": 258, "chapter": "CHƯƠNG 3", "question": "Câu 28. Đại hội đại biểu toàn quốc lần thứ V của Đảng (1982) đã thống nhất bầu ai là Tổng Bí thư của Đảng?", "options": ["A. Đ/c Lê Duẩn", "B. Đ/c Nguyễn Văn Linh", "C. Đ/c Lê Khả Phiêu", "D. Đ/c Trường Chinh"], "answer": 0, "explanation": "Đại hội V tiếp tục bầu đồng chí Lê Duẩn làm Tổng Bí thư Ban Chấp hành Trung ương Đảng (Trang 107)."},
  {"id": 259, "chapter": "CHƯƠNG 3", "question": "Câu 29. Đại hội đại biểu toàn quốc lần thứ V của Đảng (1982) đã xác định mặt trận hàng đầu trong chặng đường đầu tiên của thời kỳ quá độ lên chủ nghĩa xã hội là gì?", "options": ["A. Công nghiệp", "B. Nông nghiệp", "C. Công nghiệp nhẹ", "D. Tất cả các đáp án trên"], "answer": 1, "explanation": "Đại hội V đưa ra nhận thức mới: coi nông nghiệp là mặt trận hàng đầu trong chặng đường đầu tiên (Trang 107)."},
  {"id": 260, "chapter": "CHƯƠNG 3", "question": "Câu 30. Đại hội đại biểu toàn quốc lần thứ V của Đảng (1982) xác định: Nội dung, bước đi, cách làm để thực hiện công nghiệp hóa xã hội chủ nghĩa trong chặng đường đầu tiên là gì?", "options": ["A. Tập trung sức phát triển mạnh nông nghiệp, coi nông nghiệp là mặt trận hàng đầu, đưa nông nghiệp một bước lên sản xuất lớn xã hội chủ nghĩa", "B. Ra sức đẩy mạnh sản xuất hàng tiêu dùng; tiếp tục xây dựng một số ngành công nghiệp nặng quan trọng", "C. Kết hợp nông nghiệp với công nghiệp thành cơ cấu công – nông nghiệp hợp lý", "D. Tất cả các đáp án trên"], "answer": 3, "explanation": "Phát triển nông nghiệp kết hợp công nghiệp nhẹ, hàng tiêu dùng và công nghiệp nặng một cách có chọn lọc (Trang 107)."},
  {"id": 261, "chapter": "CHƯƠNG 3", "question": "Câu 31. Đại hội đại biểu toàn quốc lần thứ V của Đảng (1982) khẳng định chặng đường trước mặt trong những năm 80 là gì?", "options": ["A. Ổn định và cải thiện một bước đời sống vật chất, văn hóa của nhân dân", "B. Tiếp tục xây dựng cơ sở vật chất – kỹ thuật của chủ nghĩa xã hội. Thúc đẩy sản xuất nông nghiệp, hàng tiêu dùng và hàng xuất khẩu", "C. Đáp ứng nhu cầu quốc phòng, giữ vững an ninh, trật tự xã hội", "D. Tất cả các đáp án trên"], "answer": 3, "explanation": "Ổn định đời sống nhân dân, xây dựng cơ sở vật chất bước đầu và bảo đảm quốc phòng an ninh đất nước (Trang 107)."},
  {"id": 262, "chapter": "CHƯƠNG 3", "question": "Câu 32. Đại hội đại biểu toàn quốc lần thứ V của Đảng (1982) đã có những bước phát triển trong nhận thức mới, trước hết là trong lĩnh vực gì?", "options": ["A. Văn hóa – Xã hội", "B. Chính trị, An ninh quốc phòng", "C. Kinh tế", "D. Tất cả các đáp án trên"], "answer": 2, "explanation": "Nhận thức mới quan trọng nhất nằm ở tư duy kinh tế, điều chỉnh lại thứ tự ưu tiên các ngành kinh tế (Trang 107)."},
  {"id": 263, "chapter": "CHƯƠNG 3", "question": "Câu 33. Hội nghị Trung ương 8 (6/1985) được coi là bước đột phá thứ hai trong quá trình tìm tòi, đổi mới kinh tế của Đảng. Tại hội nghị này, Trung ương Đảng đã đưa ra quyết định quan trọng gì?", "options": ["A. Đổi mới toàn diện đất nước trong các ngành, lĩnh vực", "B. Xóa bỏ cơ chế tập trung quan liêu, bao cấp chuyển sang cơ chế hạch toán kinh doanh", "C. Đề ra mục tiêu đến năm 2020 nước ta trở thành nước công nghiệp hiện đại", "D. Chủ trương chuyển dùng tem phiếu sang dùng tiền mặt"], "answer": 1, "explanation": "Hội nghị Trung ương 8 quyết sách dứt khoát xóa bỏ cơ chế bao cấp, thực hiện hạch toán kinh tế xã hội chủ nghĩa (Trang 108)."},
  {"id": 264, "chapter": "CHƯƠNG 3", "question": "Câu 34. Hội nghị Bộ Chính trị khóa V (8/1986) được coi như bước đột phá thứ 3 về đổi mới kinh tế của Đảng. Hội nghị đã nhận định đặc trưng của thời kỳ quá độ lên chủ nghĩa xã hội ở nước ta là:", "options": ["A. Nền kinh tế có cơ cấu nhiều thành phần", "B. Nền kinh tế chủ yếu dựa vào các doanh nghiệp nhà nước", "C. Nền kinh tế lấy tự cung, tự cấp làm nền tảng", "D. Nền kinh tế sản xuất hàng hóa nhỏ"], "answer": 0, "explanation": "Hội nghị thừa nhận sự tồn tại tất yếu của cơ cấu kinh tế nhiều thành phần trong thời kỳ quá độ (Trang 108)."},
  {"id": 265, "chapter": "CHƯƠNG 3", "question": "Câu 35. Tổng kết 10 năm xây dựng chủ nghĩa xã hội trên phạm vi cả nước (1976-1986), cách mạng Việt Nam đã đạt một số thành tựu nổi bật, một trong đó là?", "options": ["A. Nền kinh tế có bước đột phá vượt bậc, đời sống nhân dân ngày càng được cải thiện", "B. Đưa tỷ lệ lạm phát xuống thấp kỷ lục", "C. Giành thắng lợi to lớn trong sự nghiệp bảo vệ Tổ quốc và làm nghĩa vụ quốc tế", "D. Có mối quan hệ ngoại giao với hầu hết các quốc gia trên thế giới"], "answer": 2, "explanation": "Đánh giá 10 năm, ta đạt thành tựu cơ bản nhất là bảo vệ biên cương, bờ cõi Tổ quốc và làm tròn nghĩa vụ giúp nước bạn (Trang 109)."},
  {"id": 266, "chapter": "CHƯƠNG 3", "question": "Câu 36. Nguyên nhân khách quan dẫn đến những khủng hoảng kinh tế – xã hội giai đoạn 1976-1986 là do?", "options": ["A. Sai lầm của Đảng trong đánh giá tình hình, mục tiêu và bước đi", "B. Xây dựng đất nước từ một nền kinh tế nghèo nàn, lạc hậu, bị bao vây, cấm vận nhiều năm", "C. Đảng duy trì quá lâu cơ chế quản lý tập trung quan liêu bao cấp", "D. Cả ba đáp án trên"], "answer": 1, "explanation": "Nguyên nhân khách quan là đi lên từ sản xuất nhỏ lạc hậu lại chịu tàn phá nặng nề của chiến tranh và bao vây cô lập (Trang 109)."},
  {"id": 267, "chapter": "CHƯƠNG 3", "question": "Câu 37. Bối cảnh nào tác động mạnh mẽ nhất tới quyết định tiến hành công cuộc đổi mới toàn diện đất nước mà Đại hội lần thứ VI của Đảng (1986) đã thông qua?", "options": ["A. Cuộc cách mạng khoa học – kỹ thuật đang phát triển mạnh mẽ trên thế giới", "B. Trên thế giới, xu thế đối thoại đang dần thay cho xu thế đối đầu", "C. Liên Xô và các nước xã hội chủ nghĩa đều tiến hành cải tổ sự nghiệp xây dựng chủ nghĩa xã hội", "D. Những khủng hoảng trầm trọng về kinh tế – xã hội ở Việt Nam"], "answer": 3, "explanation": "Nguyên nhân sâu xa trực tiếp nhất đòi hỏi Đảng phải đổi mới là tình trạng khủng hoảng KT-XH trầm trọng trong nước (Trang 110)."},
  {"id": 268, "chapter": "CHƯƠNG 3", "question": "Câu 38. Tinh thần \"Nhìn thẳng vào sự thật, đánh giá đúng sự thật, nói rõ sự thật\" là của Đại hội lần thứ mấy?", "options": ["A. Đại hội lần thứ III (1960)", "B. Đại hội lần thứ V (1982)", "C. Đại hội lần thứ VI (1986)", "D. Đại hội lần thứ XII (2016)"], "answer": 2, "explanation": "Đại hội VI đề cao thái độ khoa học, tự phê bình nghiêm khắc: \"Nhìn thẳng vào sự thật, đánh giá đúng sự thật\" (Trang 110)."},
  {"id": 269, "chapter": "CHƯƠNG 3", "question": "Câu 39. Tại Đại hội lần thứ VI (1986), Đảng Cộng sản Việt Nam đã chỉ ra những sai lầm, khuyết điểm trong lãnh đạo, chỉ đạo ở thời kỳ 1975-1986, đâu là khuyết điểm quyết định nhất?", "options": ["A. Những sai lầm nghiêm trọng và kéo dài về chủ trương, chính sách lớn", "B. Những sai lầm nghiêm trọng về chỉ đạo chiến lược và tổ chức thực hiện", "C. Do chủ quan duy ý chí, suy nghĩ và hành động giản đơn, nóng vội, chạy theo nguyện vọng chủ quan", "D. Những khuyết điểm trong hoạt động tư tưởng, tổ chức và công tác cán bộ của Đảng"], "answer": 0, "explanation": "Khuyết điểm lớn nhất là những sai lầm chủ quan, duy ý chí kéo dài về các chủ trương, chính sách lớn của Đảng (Trang 110)."},
  {"id": 270, "chapter": "CHƯƠNG 3", "question": "Câu 40. Đường lối đổi mới toàn diện, đưa đất nước ra khỏi khủng hoảng kinh tế – xã hội được đưa ra tại Đại hội lần thứ mấy?", "options": ["A. Đại hội lần thứ V (1982)", "B. Đại hội lần thứ VI (1986)", "C. Đại hội lần thứ VII (1991)", "D. Đại hội lần thứ VIII (1996)"], "answer": 1, "explanation": "Đại hội VI (12/1986) đặt cột mốc lịch sử khởi xướng đường lối đổi mới toàn diện đất nước (Trang 110)."},
  {"id": 271, "chapter": "CHƯƠNG 3", "question": "Câu 41. Đại hội đại biểu toàn quốc lần thứ VI của Đảng (1986) bầu đồng chí nào làm Tổng Bí thư?", "options": ["A. Đ/c Lê Duẩn", "B. Đ/c Trường Chinh", "C. Đ/c Võ Văn Kiệt", "D. Đ/c Nguyễn Văn Linh"], "answer": 3, "explanation": "Đồng chí Nguyễn Văn Linh – người ủng hộ đổi mới tư duy mạnh mẽ được bầu làm Tổng Bí thư (Trang 110)."},
  {"id": 272, "chapter": "CHƯƠNG 3", "question": "Câu 42. Đại hội đại biểu toàn quốc lần thứ VI của Đảng (1986) là Đại hội của …?", "options": ["A. Công cuộc xây dựng chủ nghĩa xã hội", "B. Xây dựng và phát triển kinh tế", "C. Công cuộc đổi mới toàn diện đất nước", "D. Xây dựng và chỉnh đốn Đảng"], "answer": 2, "explanation": "Đại hội VI được lịch sử ghi nhận là Đại hội của công cuộc đổi mới toàn diện đất nước (Trang 110)."},
  {"id": 273, "chapter": "CHƯƠNG 3", "question": "Câu 43. Đại hội lần thứ VI của Đảng (1986) đã xác định rõ quan điểm đổi mới của Đảng Cộng sản Việt Nam là đổi mới toàn diện và đồng bộ, nhưng quan trọng nhất là gì?", "options": ["A. Đổi mới về chính trị", "B. Đổi mới về kinh tế và chính trị", "C. Đổi mới về kinh tế", "D. Đổi mới về văn hóa"], "answer": 2, "explanation": "Trọng tâm của đổi mới trong chặng đường đầu tiên là đổi mới kinh tế để khôi phục sức sản xuất (Trang 110)."},
  {"id": 274, "chapter": "CHƯƠNG 3", "question": "Câu 44. Đại hội lần thứ VI của Đảng (1986) đã xác định nhiệm vụ bao trùm, mục tiêu tổng quát cho chặng đường đầu tiên của thời kỳ quá độ lên chủ nghĩa xã hội ở Việt Nam. Theo đó, nhiệm vụ nào được chú trọng đặc biệt?", "options": ["A. Sản xuất đủ tiêu dùng và có tích lũy", "B. Bước đầu tạo ra một cơ cấu kinh tế hợp lý", "C. Thực hiện ba chương trình kinh tế lớn là lương thực – thực phẩm, hàng tiêu dùng và hàng xuất khẩu", "D. Đổi mới cơ chế quản lý, xóa bỏ cơ chế tập trung quan liêu hành chính bao cấp"], "answer": 2, "explanation": "Ba chương trình kinh tế lớn (Lương thực thực phẩm, Hàng tiêu dùng, Hàng xuất khẩu) là hạt nhân đổi mới kinh tế (Trang 110)."},
  {"id": 275, "chapter": "CHƯƠNG 3", "question": "Câu 45. Đại hội lần thứ VI của Đảng (1986) đã xác định việc đổi mới cơ chế quản lý kinh tế là để giải quyết cho được vấn đề nào dưới đây?", "options": ["A. Tình trạng khan hiếm trầm trọng về lương thực – thực phẩm và hàng tiêu dùng", "B. Những vấn đề cấp bách trong phân phối và lưu thông", "C. Tình trạng \"xin – cho\" đang diễn ra phổ biến trong nền kinh tế Việt Nam", "D. Đảm bảo nhu cầu củng cố quốc phòng và an ninh"], "answer": 1, "explanation": "Mục tiêu đổi mới cơ chế là giải quyết các bất cập, ách tắc lớn trong phân phối và lưu thông hàng hóa (Trang 110)."},
  {"id": 276, "chapter": "CHƯƠNG 3", "question": "Câu 46. Đại hội lần thứ VI của Đảng (1986) đã xác định việc thực hiện cải tạo xã hội chủ nghĩa thường xuyên với hình thức, bước đi thích hợp:", "options": ["A. Làm cho lực lượng sản xuất ở Việt Nam phát triển một cách nhanh chóng", "B. Làm cho quan hệ sản xuất trở lên ưu việt", "C. Làm cho quan hệ sản xuất phù hợp và lực lượng sản xuất phát triển", "D. Làm cho các chính sách xã hội được thực hiện một cách thiết thực và hiệu quả"], "answer": 2, "explanation": "Thực hiện cải tạo quan hệ sản xuất sao cho phù hợp với trình độ phát triển của lực lượng sản xuất thực tế (Trang 111)."},
  {"id": 277, "chapter": "CHƯƠNG 3", "question": "Câu 47. Nội dung nào sau đây không phải là một trong năm phương hướng lớn phát triển kinh tế được Đại hội lần thứ VI của Đảng (1986) thông qua?", "options": ["A. Bố trí lại cơ cấu sản xuất", "B. Điều chỉnh cơ cấu đầu tư xây dựng và củng cố quan hệ sản xuất xã hội chủ nghĩa", "C. Sử dụng và cải tạo đúng đắn các thành phần kinh tế", "D. Cẩn trọng trong mở rộng và nâng cao hiệu quả kinh tế đối ngoại với các nước tư bản chủ nghĩa"], "answer": 3, "explanation": "Chủ trương của Đại hội VI là chủ động mở rộng quan hệ đối ngoại và thu hút đầu tư, không có ý cẩn trọng tiêu cực (Trang 111)."},
  {"id": 278, "chapter": "CHƯƠNG 3", "question": "Câu 48. Đường lối đối ngoại của Đảng được đề ra tại Đại hội lần thứ VI (1986) là gì?", "options": ["A. Bình thường hóa quan hệ với Trung Quốc vì lợi ích của Việt Nam", "B. Bình thường hóa với các nước xã hội chủ nghĩa và tăng cường tình hữu nghị, hợp tác toàn diện với Liên Xô", "C. Bình thường hóa quan hệ với Mỹ vì lợi ích kinh tế", "D. Quan hệ hữu nghị và hợp tác toàn diện với Liên Xô và các nước xã hội chủ nghĩa"], "answer": 3, "explanation": "Ưu tiên đối ngoại hàng đầu của thời kỳ này vẫn là đoàn kết với Liên Xô và hệ thống các nước XHCN (Trang 111)."},
  {"id": 279, "chapter": "CHƯƠNG 3", "question": "Câu 49. Đại hội lần thứ VI của Đảng (1986) thông qua đường lối đối ngoại, trong đó nhấn mạnh tăng cường quan hệ đặc biệt với:", "options": ["A. Liên Xô và các nước xã hội chủ nghĩa", "B. Trung Quốc", "C. Lào và Campuchia", "D. Các nước thuộc phong trào không liên kết"], "answer": 2, "explanation": "Về quan hệ láng giềng Đông Dương, khẳng định củng cố tình đoàn kết đặc biệt với hai nước Lào và Campuchia (Trang 111)."},
  {"id": 280, "chapter": "CHƯƠNG 3", "question": "Câu 50. Đại hội lần thứ VI của Đảng (1986) xác định đổi mới sự lãnh đạo của Đảng cần phải đổi mới tư duy, trước hết là:", "options": ["A. Tư duy kinh tế", "B. Tư duy về công tác cán bộ", "C. Tư duy về quan hệ đối ngoại của Việt Nam", "D. Tư duy về an sinh xã hội"], "answer": 0, "explanation": "Đổi mới sự lãnh đạo của Đảng yêu cầu đổi mới tư duy toàn diện, trước hết là đổi mới tư duy kinh tế (Trang 111)."},
  {"id": 281, "chapter": "CHƯƠNG 3", "question": "Câu 51. Nội dung nào dưới đây không phải là thành công của Đại hội lần thứ VI (1986)?", "options": ["A. Đại hội đã khởi xướng đường lối đổi mới toàn diện đất nước", "B. Đại hội đã đánh dấu bước phát triển mới trong thời kỳ quá độ lên chủ nghĩa xã hội", "C. Đại hội đã đề ra các giải pháp hiệu quả tháo gỡ tình trạng rối ren trong phân phối và lưu thông", "D. Đại hội đã thông qua các văn kiện mang tính chất khoa học và cách mạng"], "answer": 2, "explanation": "Mặc dù đề ra phương hướng nhưng sau Đại hội VI, các khó khăn trong lưu thông phân phối vẫn tiếp diễn phức tạp (Trang 112)."},
  {"id": 282, "chapter": "CHƯƠNG 3", "question": "Câu 52. Trong quá trình thực hiện Nghị quyết Đại hội lần thứ VI của Đảng (1986), khó khăn lớn nhất là?", "options": ["A. Liên Xô và các nước xã hội chủ nghĩa Đông Âu ngày càng rơi vào khủng hoảng toàn diện", "B. Viện trợ và quan hệ kinh tế giữa hai bên bị thu hẹp nhanh chóng", "C. Mỹ và các thế lực thù địch tiếp tục bao vây, cấm vận", "D. Sự dao động về tư tưởng chính trị, giảm sút niềm tin vào con đường xã hội chủ nghĩa"], "answer": 0, "explanation": "Biến động chính trị và khủng hoảng toàn diện ở các nước Đông Âu, Liên Xô là bất lợi quốc tế lớn nhất (Trang 112)."},
  {"id": 283, "chapter": "CHƯƠNG 3", "question": "Câu 53. Việc Hội nghị Trung ương 2 (04/1987) đề ra một số biện pháp cấp bách về phân phối, lưu thông đã giải quyết được hạn chế còn tồn tại của Đại hội nào dưới đây?", "options": ["A. Đại hội V (1982)", "B. Đại hội VI (1986)", "C. Đại hội VII (1991)", "D. Đại hội VIII (1996)"], "answer": 1, "explanation": "Hội nghị Trung ương 2 khóa VI họp tháng 4/1987 nhằm cụ thể hóa và khắc phục các lúng túng sau Đại hội VI (Trang 112)."},
  {"id": 284, "chapter": "CHƯƠNG 3", "question": "Câu 54. Triển khai Nghị quyết Đại hội lần thứ VI của Đảng (1986) vào cuộc sống, nội dung nào dưới đây là không đúng về việc thực hiện cải tạo xã hội chủ nghĩa?", "options": ["A. Nhà nước công nhận sự tồn tại lâu dài của nhiều thành phần kinh tế", "B. Nâng cao vai trò chủ đạo của nền kinh tế tập thể", "C. Phát huy khả năng tích cực của các thành phần kinh tế", "D. Các thành phần kinh tế bình đẳng về quyền lợi, nghĩa vụ trước pháp luật"], "answer": 1, "explanation": "Trong cải tạo quan hệ sản xuất, Đảng khẳng định vai trò chủ đạo của kinh tế Nhà nước, không phải kinh tế tập thể (Trang 112)."},
  {"id": 285, "chapter": "CHƯƠNG 3", "question": "Câu 55. Nghị quyết 10 của Bộ Chính trị (4/1988) về khoán sản phẩm cuối cùng đến nhóm hộ và hộ xã viên (gọi tắt là khoán 10) được diễn ra trong lĩnh vực nào?", "options": ["A. Công nghiệp", "B. Thương nghiệp", "C. Nông nghiệp", "D. Lâm nghiệp"], "answer": 2, "explanation": "Khoán 10 là bước ngoặt vĩ đại giải phóng sức sản xuất trong nông nghiệp Việt Nam (Trang 112)."},
  {"id": 286, "chapter": "CHƯƠNG 3", "question": "Câu 56. Hội nghị Trung ương 6 (3/1989) đề ra sáu nguyên tắc chỉ đạo công cuộc đổi mới. Nguyên tắc nào dưới đây được coi là điều kiện quyết định thắng lợi sự nghiệp xây dựng và bảo vệ Tổ quốc?", "options": ["A. Kiên định con đường đi lên chủ nghĩa xã hội", "B. Sự lãnh đạo của Đảng Cộng sản Việt Nam", "C. Xây dựng nền dân chủ xã hội chủ nghĩa", "D. Kết hợp sức mạnh dân tộc với sức mạnh thời đại"], "answer": 1, "explanation": "Giữ vững vai trò lãnh đạo duy nhất của Đảng Cộng sản Việt Nam là nguyên tắc sống còn, quyết định thắng lợi (Trang 113)."},
  {"id": 287, "chapter": "CHƯƠNG 3", "question": "Câu 57. Hội nghị Trung ương 6 (3/1989) đề ra sáu nguyên tắc chỉ đạo công cuộc đổi mới. Nội dung nào dưới đây không phải là một trong sáu nguyên tắc đó?", "options": ["A. Đi lên chủ nghĩa xã hội là con đường tất yếu của nước ta", "B. Chủ nghĩa Mác – Lênin cùng với tư tưởng Hồ Chí Minh là nền tảng tư tưởng của Đảng", "C. Xây dựng nền dân chủ xã hội chủ nghĩa là mục tiêu, động lực của sự nghiệp", "D. Kết hợp sức mạnh dân tộc với sức mạnh thời đại"], "answer": 3, "explanation": "'Kết hợp sức mạnh dân tộc với sức mạnh thời đại' là phương châm chỉ đạo chiến lược, không nằm trong 6 nguyên tắc cốt lõi (Trang 113)."},
  {"id": 288, "chapter": "CHƯƠNG 3", "question": "Câu 58. Nội dung nào dưới đây không phải là mục tiêu của việc đổi mới tổ chức và phương thức hoạt động của hệ thống chính trị mà Hội nghị Trung ương 6 (3/1989) đề ra?", "options": ["A. Tăng cường vai trò lãnh đạo của Đảng", "B. Nâng cao hiệu quả quản lý của Nhà nước", "C. Phát huy quyền làm chủ của nhân dân", "D. Nâng cao hơn nữa hiệu quả của công tác kết hợp sức mạnh dân tộc với sức mạnh thời đại"], "answer": 3, "explanation": "Hội nghị chỉ tập trung đổi mới hệ thống chính trị quốc nội gồm Đảng, Nhà nước và các đoàn thể (Trang 113)."},
  {"id": 289, "chapter": "CHƯƠNG 3", "question": "Câu 59. Tại sao vào tháng 9 năm 1989 (sớm hơn một năm theo kế hoạch), Việt Nam rút hết quân tình nguyện ở Campuchia về nước?", "options": ["A. Do tình hình ở Campuchia đã hoàn toàn ổn định", "B. Do Việt Nam cần lực lượng để ổn định biên giới phía Bắc với Trung Quốc", "C. Do Việt Nam chịu sức ép từ các nước trên thế giới", "D. Do thực hiện chủ trương đổi mới về quan hệ đối ngoại của Đảng"], "answer": 3, "explanation": "Việc rút hết quân về nước thể hiện thiện chí hòa bình, tháo gỡ thế bao vây cô lập theo đường lối ngoại giao mới (Trang 113)."},
  {"id": 290, "chapter": "CHƯƠNG 3", "question": "Câu 60. Hội nghị Trung ương 8 (3/1990) đã chỉ ra nguyên nhân sâu xa dẫn đến khủng hoảng ở Liên Xô và các nước xã hội chủ nghĩa Đông Âu là:", "options": ["A. Những quan điểm, khuynh hướng sai lầm, hữu khuynh của một số người lãnh đạo", "B. Các thế lực thù địch tăng cường can thiệp, phá hoại, thực hiện \"diễn biến hòa bình\"", "C. Việc xây dựng mô hình chủ nghĩa xã hội còn một số nhược điểm và khuyết điểm kéo dài quá lâu, ngày càng nặng nề", "D. Nhân dân hoài nghi với chủ nghĩa xã hội"], "answer": 2, "explanation": "Nguyên nhân sâu xa là các khuyết tật của mô hình CNXH hiện thực kiểu cũ không được sửa chữa kịp thời (Trang 113)."},
  {"id": 291, "chapter": "CHƯƠNG 3", "question": "Câu 61. Hội nghị Trung ương 8 (3/1990) đã kịp thời phân tích tình hình các nước xã hội chủ nghĩa. Bài học rút ra cho những người cộng sản Việt Nam là?", "options": ["A. Đổi mới nhận thức về mô hình và con đường xây dựng chủ nghĩa xã hội", "B. Đổi mới nhận thức về tình hình thế giới và khu vực", "C. Đổi mới nhận thức về sức mạnh trong nước kết hợp với sức mạnh thời đại", "D. Đổi mới nhận thức về mối quan hệ đối ngoại"], "answer": 0, "explanation": "Bài học lớn nhất là phải kiên quyết đổi mới tư duy, nhận thức rõ mô hình và con đường đi lên CNXH phù hợp (Trang 113)."},
  {"id": 292, "chapter": "CHƯƠNG 3", "question": "Câu 62. Bắt đầu từ năm 1990, Đảng và Nhà nước Việt Nam đưa ra chủ trương bình thường hóa quan hệ với những nước nào trên thế giới?", "options": ["A. Trung Quốc, Hoa Kỳ", "B. Các nước thuộc khối Liên minh Châu Âu (EU)", "C. Pháp, Hoa Kỳ", "D. Trung Quốc, Pháp"], "answer": 0, "explanation": "Từ 1990, Việt Nam tích cực triển khai ngoại giao bình thường hóa quan hệ với Trung Quốc và Mỹ (Trang 114)."},
  {"id": 293, "chapter": "CHƯƠNG 3", "question": "Câu 63. Hội nghị Trung ương 6 (3/1989) and Hội nghị Trung ương 8 (3/1990) tập trung giải quyết những vấn đề cấp bách trong công tác xây dựng Đảng có điểm nổi bật là đổi mới tư duy, nhất là:", "options": ["A. Tư duy kinh tế", "B. Tư duy về chất lượng đội ngũ đảng viên", "C. Tư duy về mối quan hệ giữa Đảng với nhân dân", "D. Tư duy về công tác giáo dục chính trị, tư tưởng"], "answer": 3, "explanation": "Đảng nhấn mạnh yêu cầu hàng đầu là đổi mới sâu sắc công tác giáo dục chính trị và tư tưởng trong toàn Đảng (Trang 114)."},
  {"id": 294, "chapter": "CHƯƠNG 3", "question": "Câu 64. Đại hội lần thứ mấy của Đảng được gọi là Đại hội \"Trí tuệ, đổi mới, dân chủ, kỷ cương và đoàn kết\"?", "options": ["A. Đại hội lần thứ V (1982)", "B. Đại hội lần thứ VI (1986)", "C. Đại hội lần thứ VII (1991)", "D. Đại hội lần thứ VIII (1996)"], "answer": 2, "explanation": "Đại hội đại biểu toàn quốc lần thứ VII (6/1991) đề ra khẩu hiệu hành động lịch sử này (Trang 115)."},
  {"id": 295, "chapter": "CHƯƠNG 3", "question": "Câu 65. Đại hội đại biểu toàn quốc lần thứ VII của Đảng (1991) đã bầu đồng chí nào làm Tổng Bí thư?", "options": ["A. Đ/c Đỗ Mười", "B. Đ/c Nông Đức Mạnh", "C. Đ/c Lê Khả Phiêu", "D. Đ/c Nguyễn Văn Linh"], "answer": 0, "explanation": "Đồng chí Đỗ Mười được bầu làm Tổng Bí thư tại Đại hội VII (Trang 115)."},
  {"id": 296, "chapter": "CHƯƠNG 3", "question": "Câu 66. Đại hội nào của Đảng khẳng định: \"Đảng Cộng sản Việt Nam lấy chủ nghĩa Mác – Lênin và tư tưởng Hồ Chí Minh là nền tảng tư tưởng và kim chỉ nam cho hành động\"?", "options": ["A. Đại hội lần thứ VI (1986)", "B. Đại hội lần thứ VII (1991)", "C. Đại hội lần thứ VIII (1996)", "D. Đại hội lần thứ IX (2001)"], "answer": 1, "explanation": "Đại hội VII bổ sung tư tưởng Hồ Chí Minh vào nền tảng tư tưởng, kim chỉ nam cho hành động của Đảng (Trang 115)."},
  {"id": 297, "chapter": "CHƯƠNG 3", "question": "Câu 67. Cương lĩnh xây dựng đất nước trong thời kỳ quá độ lên chủ nghĩa xã hội được thông qua trong Đại hội lần thứ mấy của Đảng?", "options": ["A. Đại hội lần thứ VI (1986)", "B. Đại hội lần thứ VII (1991)", "C. Đại hội lần thứ VIII (1996)", "D. Đại hội lần thứ IX (2001)"], "answer": 1, "explanation": "Bản Cương lĩnh xây dựng đất nước thời kỳ quá độ lên CNXH (Cương lĩnh 1991) được Đại hội VII thông qua (Trang 115)."},
  {"id": 298, "chapter": "CHƯƠNG 3", "question": "Câu 68. Cương lĩnh xây dựng đất nước trong thời kỳ quá độ lên chủ nghĩa xã hội được thông qua tại Đại hội lần thứ VII (1991) là Cương lĩnh thứ mấy của Đảng?", "options": ["A. Cương lĩnh thứ nhất", "B. Cương lĩnh thứ hai", "C. Cương lĩnh thứ ba", "D. Cương lĩnh thứ tư"], "answer": 2, "explanation": "Đây là Cương lĩnh thứ ba của Đảng (sau Cương lĩnh 1930 và Chính cương 1951) (Trang 115)."},
  {"id": 299, "chapter": "CHƯƠNG 3", "question": "Câu 70. Theo Cương lĩnh xây dựng đất nước trong thời kỳ quá độ lên chủ nghĩa xã hội (năm 1991), thành tố nào dưới đây được xác định có vai trò lãnh đạo hệ thống chính trị?", "options": ["A. Đảng Cộng sản Việt Nam", "B. Nhà nước xã hội chủ nghĩa Việt Nam", "C. Mặt trận Tổ quốc và các đoàn thể nhân dân", "D. Tất cả các đáp án"], "answer": 0, "explanation": "Cương lĩnh khẳng định Đảng Cộng sản Việt Nam là lực lượng lãnh đạo Nhà nước và xã hội (Trang 116)."},
  {"id": 300, "chapter": "CHƯƠNG 3", "question": "Câu 71. Theo Cương lĩnh xây dựng đất nước trong thời kỳ quá độ lên chủ nghĩa xã hội (năm 1991), nền tảng tư tưởng và kim chỉ nam cho hành động của Đảng Cộng sản Việt Nam là?", "options": ["A. Chủ nghĩa Mác – Lênin", "B. Chủ nghĩa Mác – Lênin và tư tưởng Hồ Chí Minh", "C. Tư tưởng tập trung dân chủ", "D. Tư tưởng đi lên chủ nghĩa xã hội là yêu cầu khách quan"], "answer": 1, "explanation": "Đảng lấy chủ nghĩa Mác - Lênin và tư tưởng Hồ Chí Minh làm nền tảng tư tưởng (Trang 115)."},
  {"id": 301, "chapter": "CHƯƠNG 3", "question": "Câu 72. Việt Nam và Trung Quốc bình thường hóa quan hệ và từng bước khôi phục, mở rộng quan hệ hữu nghị, hợp tác nhiều mặt vào tháng/năm nào?", "options": ["A. 11/1990", "B. 11/1991", "C. 11/1992", "D. 11/1993"], "answer": 1, "explanation": "Quan hệ Việt - Trung chính thức được bình thường hóa vào tháng 11/1991 (Trang 114)."},
  {"id": 302, "chapter": "CHƯƠNG 3", "question": "Câu 73. Luận điểm nào dưới đây là một trong sáu đặc trưng của xã hội xã hội chủ nghĩa mà Cương lĩnh xây dựng đất nước trong thời kỳ quá độ lên chủ nghĩa xã hội (năm 1991) đã xác định?", "options": ["A. Có một nền kinh tế phát triển cao dựa trên lực lượng sản xuất hiện đại và chế độ tư hữu về tư liệu sản xuất", "B. Có một nền kinh tế phát triển cao dựa trên lực lượng sản xuất hiện đại và chế độ công hữu về tư liệu sản xuất chủ yếu", "C. Có một nền văn hóa tiên tiến, giao lưu và hội nhập quốc tế", "D. Có quan hệ hữu nghị và hợp tác với nhân dân các nước xã hội chủ nghĩa trên thế giới"], "answer": 1, "explanation": "Cương lĩnh xác định đặc trưng kinh tế là phát triển cao dựa trên công hữu về tư liệu sản xuất chủ yếu (Trang 116)."},
  {"id": 303, "chapter": "CHƯƠNG 3", "question": "Câu 74. Theo Cương lĩnh xây dựng đất nước trong thời kỳ quá độ lên chủ nghĩa xã hội (năm 1991), nội dung nào dưới đây giữ vị trí chủ đạo trong đời sống tinh thần xã hội?", "options": ["A. Thế giới quan Mác – Lênin", "B. Thế giới quan Mác – Lênin, tư tưởng, đạo đức Hồ Chí Minh", "C. Thế giới quan Mác – Lênin, tư tưởng, đạo đức, phong cách Hồ Chí Minh", "D. Thế giới quan Mác – Lênin, tư tưởng, đạo đức, phong cách Hồ Chí Minh và truyền thống văn hóa dân tộc"], "answer": 1, "explanation": "Chủ nghĩa Mác - Lênin và tư tưởng Hồ Chí Minh giữ vị trí chủ đạo trong đời sống tinh thần xã hội (Trang 116)."},
  {"id": 304, "chapter": "CHƯƠNG 3", "question": "Câu 75. Đại hội lần thứ VII của Đảng (1991) đã xác định mục tiêu tổng quát đến năm 2000 của Việt Nam là phấn đấu vượt qua tình trạng nước nghèo và kém phát triển. Theo đó, mục tiêu và động lực chính của sự phát triển là?", "options": ["A. Vị trí của Việt Nam trên trường quốc tế", "B. Vì sự tồn tại và lãnh đạo của Đảng Cộng sản Việt Nam", "C. Vì con người, do con người, giải phóng sức sản xuất, khơi gợi mọi tiềm năng của cá nhân, tập thể và cả cộng đồng dân tộc", "D. Sự tin tưởng và ủng hộ tuyệt đối của nhân dân với Đảng"], "answer": 2, "explanation": "Nhân tố trung tâm là giải phóng mọi nguồn lực xã hội vì sự phát triển toàn diện của con người (Trang 117)."},
  {"id": 305, "chapter": "CHƯƠNG 3", "question": "Câu 76. Hội nghị Trung ương 3 (6/1992) lần đầu tiên đưa ra chủ trương đổi mới, tự chỉnh đốn Đảng, mục tiêu được xác định là gì?", "options": ["A. Nâng cao năng lực lãnh đạo và sức chiến đấu của Đảng, phù hợp với yêu cầu khách quan của cách mạng Việt Nam trong tình hình mới", "B. Củng cố, bảo vệ vai trò lãnh đạo duy nhất của Đảng Cộng sản Việt Nam trước sự chống phá", "C. Củng cố, tăng cường niềm tin của nhân dân vào sự lãnh đạo của Đảng", "D. Nâng cao năng lực lãnh đạo của Đảng để thực hiện thắng lợi công cuộc đổi mới đất nước"], "answer": 0, "explanation": "Hội nghị đề ra yêu cầu nâng cao năng lực và sức chiến đấu của Đảng trước những biến động thế giới (Trang 117)."},
  {"id": 306, "chapter": "CHƯƠNG 3", "question": "Câu 77. Điểm mới của Nghị quyết số 05-NQ/TƯ ngày 10/6/1993 về tiếp tục đổi mới và phát triển kinh tế – xã hội nông thôn là?", "options": ["A. Đề ra các chính sách làm cho sản xuất trong nông nghiệp được \"bung ra\"", "B. Chủ trương coi nông nghiệp là mặt trận hàng đầu", "C. Đổi mới quản lý kinh tế nông nghiệp, nông dân được nhận khoán và canh tác trên diện tích ổn định trong 15 năm", "D. Đề ra các quan điểm, nhiệm vụ xây dựng, phát triển nông nghiệp, nông thôn toàn diện, khơi dậy mọi tiềm năng, nội lực của nông dân"], "answer": 3, "explanation": "Nghị quyết 05 đặt trọng tâm phát triển nông thôn toàn diện, tôn trọng quyền tự chủ làm giàu của nông dân (Trang 117)."},
  {"id": 307, "chapter": "CHƯƠNG 3", "question": "Câu 78. Nội dung nào dưới đây là không đúng về Hội nghị đại biểu toàn quốc giữa nhiệm kỳ khóa VII của Đảng (1/1994)?", "options": ["A. Là Hội nghị đại biểu toàn quốc giữa nhiệm kỳ lần đầu tiên Đảng tổ chức", "B. Là Hội nghị lần đầu tiên khẳng định Đảng Cộng sản Việt Nam lấy chủ nghĩa Mác – Lênin, tư tưởng Hồ Chí Minh làm nền tảng", "C. Là Hội nghị lần đầu tiên khẳng định xây dựng Nhà nước pháp quyền Việt Nam", "D. Là Hội nghị lần đầu tiên chỉ rõ 4 nguy cơ của cách mạng Việt Nam"], "answer": 1, "explanation": "Khẳng định lấy chủ nghĩa Mác-Lênin, tư tưởng Hồ Chí Minh làm nền tảng đã có từ Đại hội VII năm 1991 (Trang 118)."},
  {"id": 308, "chapter": "CHƯƠNG 3", "question": "Câu 79. \"Nước ta đã ra khỏi khủng hoảng kinh tế – xã hội, nhưng một số mặt còn chưa vững chắc\" là đánh giá tổng quát của Đại hội lần thứ mấy?", "options": ["A. Đại hội lần thứ VI (1986)", "B. Đại hội lần thứ VII (1991)", "C. Đại hội lần thứ VIII (1996)", "D. Đại hội lần thứ IX (2001)"], "answer": 2, "explanation": "Đại hội VIII tuyên bố Việt Nam chính thức thoát khỏi khủng hoảng kinh tế - xã hội kéo dài (Trang 120)."},
  {"id": 310, "chapter": "CHƯƠNG 3", "question": "Câu 80. Tổng kết 10 năm đổi mới đất nước (1986-1996), Đại hội lần thứ VIII của Đảng (1996) khẳng định đất nước đã thu được những thành tựu to lớn, có ý nghĩa rất quan trọng, một trong những thành tựu đó là?", "options": ["A. Nước ta đã ra khỏi khủng hoảng kinh tế – xã hội, nhưng một số mặt còn chưa vững chắc", "B. Nước ta đã ra khỏi khủng hoảng kinh tế – xã hội, có sự thay đổi cơ bản và toàn diện", "C. Công nghiệp hóa, hiện đại hóa đất nước bước đầu tạo ra những kết quả tốt đẹp", "D. Vị thế nước ta trên trường quốc tế không ngừng được nâng cao"], "answer": 0, "explanation": "Đại hội VIII đánh giá tổng quát: Đất nước đã ra khỏi khủng hoảng kinh tế - xã hội (Trang 120)."},
  {"id": 311, "chapter": "CHƯƠNG 3", "question": "Câu 81. Đại hội đại biểu toàn quốc lần thứ VIII của Đảng (1996) đã bầu đồng chí nào làm Tổng Bí thư?", "options": ["A. Đ/c Lê Duẩn", "B. Đ/c Trường Chinh", "C. Đ/c Đỗ Mười", "D. Đ/c Lê Khả Phiêu"], "answer": 2, "explanation": "Đại hội VIII tiếp tục bầu đồng chí Đỗ Mười giữ trọng trách Tổng Bí thư (Trang 120)."},
  {"id": 312, "chapter": "CHƯƠNG 3", "question": "Câu 82. Quyết sách quan trọng nhất của Đại hội VIII (1996) đánh dấu bước phát triển mới của cách mạng Việt Nam là gì?", "options": ["A. Bình thường hóa quan hệ với Hoa Kỳ", "B. Bình thường hóa quan hệ với Trung Quốc", "C. Đẩy mạnh công nghiệp hóa, hiện đại hóa đất nước", "D. Gia nhập Tổ chức Hiệp hội các nước Đông Nam Á (ASEAN)"], "answer": 2, "explanation": "Đại hội VIII đề ra quyết sách lịch sử chuyển sang thời kỳ đẩy mạnh công nghiệp hóa, hiện đại hóa đất nước (Trang 120)."},
  {"id": 313, "chapter": "CHƯƠNG 3", "question": "Câu 83. Trong Báo cáo chính trị tại Đại hội lần thứ VIII của Đảng (1996) khẳng định: Những thành tựu đổi mới thu được đã chứng tỏ điều gì?", "options": ["A. Đường lối đổi mới của Đảng đề ra là hoàn toàn đúng đắn", "B. Thể hiện sự đúng đắn trong việc kiên trì con đường đi lên chủ nghĩa xã hội", "C. Trí tuệ của toàn Đảng và ý chí của toàn dân Việt Nam", "D. Vai trò lãnh đạo duy nhất của Đảng Cộng sản Việt Nam"], "answer": 2, "explanation": "Thành tựu chứng minh đường lối đổi mới kết tinh trí tuệ của toàn Đảng và ý chí của toàn dân (Trang 121)."},
  {"id": 314, "chapter": "CHƯƠNG 3", "question": "Câu 84. Nghị quyết Hội nghị Trung ương 2 khóa VIII (12/1996) đề ra nhiều mục tiêu về phát triển khoa học và công nghệ, đâu không phải là một trong những mục tiêu đó?", "options": ["A. Nâng cao năng lực và hiệu quả hoạt động khoa học và công nghệ trong nước", "B. Từng bước làm chủ các công nghệ then chốt để phục vụ đắc lực sự nghiệp", "C. Tiếp thu và làm chủ các thành tựu khoa học hiện đại của nhân loại", "D. Mục tiêu cơ bản là cải thiện chất lượng cuộc sống cho người lao động nghèo"], "answer": 3, "explanation": "Khoa học công nghệ phục vụ CNH-HĐH, mục tiêu cải thiện cuộc sống người nghèo thuộc chương trình an sinh xã hội (Trang 121)."},
  {"id": 315, "chapter": "CHƯƠNG 3", "question": "Câu 85. Nghị quyết Hội nghị Trung ương 2 khóa VIII (12/1996) khẳng định giáo dục và đào tạo cùng với khoa học và công nghệ là:", "options": ["A. Tiền đề cốt lõi", "B. Quốc sách hàng đầu", "C. Mục tiêu chiến lược", "D. Hạt nhân cơ bản"], "answer": 1, "explanation": "Nghị quyết khẳng định Giáo dục - Đào tạo và Khoa học - Công nghệ là quốc sách hàng đầu (Trang 121)."},
  {"id": 316, "chapter": "CHƯƠNG 3", "question": "Câu 86. Để phát huy vai trò và nguồn lực của văn hóa đối với sự nghiệp xây dựng chủ nghĩa xã hội, Hội nghị Trung ương 5 khóa VIII (7/1998) đã thông qua Nghị quyết về xây dựng và phát triển nền văn hóa Việt Nam:", "options": ["A. Tiên tiến", "B. Đậm đà bản sắc dân tộc", "C. Tiên tiến, đậm đà bản sắc dân tộc", "D. Hội nhập quốc tế, đậm đà bản sắc dân tộc"], "answer": 2, "explanation": "Hội nghị thông qua Nghị quyết xây dựng nền văn hóa Việt Nam tiên tiến, đậm đà bản sắc dân tộc (Trang 121)."},
  {"id": 317, "chapter": "CHƯƠNG 3", "question": "Câu 87. Hội nghị Trung ương 6 lần 2 khóa VIII (1999) đã thông qua Nghị quyết về một số vấn đề cơ bản, cấp bách trong công tác xây dựng Đảng, nhiệm vụ nào được đặt lên hàng đầu?", "options": ["A. Đấu tranh chống suy thoái đạo đức, lối sống", "B. Đấu tranh chống tham nhũng, lãng phí và tệ quan liêu", "C. Nâng cao vai trò lãnh đạo và sức chiến đấu của tổ chức cơ sở đảng", "D. Thực hiện nghiêm chỉnh nguyên tắc tập trung dân chủ"], "answer": 1, "explanation": "Trọng tâm cấp bách là cuộc đấu tranh chống tham nhũng, lãng phí và quan liêu trong bộ máy (Trang 122)."},
  {"id": 318, "chapter": "CHƯƠNG 3", "question": "Câu 88. Hội nghị Trung ương 6 lần 2 khóa VIII (1999) xác định nhân tố quyết định bảo đảm cho công tác tự chỉnh đốn Đảng thành công là?", "options": ["A. Vận dụng và phát triển sáng tạo chủ nghĩa Mác – Lênin và tư tưởng Hồ Chí Minh", "B. Giữ vững tính chất giai cấp công nhân của Đảng", "C. Đảng phải thực sự dựa vào dân, lắng nghe ý kiến phản ánh, phê bình của nhân dân", "D. Nêu cao tinh thần tự phê bình và phê bình của đội ngũ cán bộ, đảng viên"], "answer": 0, "explanation": "Nhân tố quyết định là kiên định và phát triển sáng tạo chủ nghĩa Mác-Lênin, tư tưởng Hồ Chí Minh (Trang 122)."},
  {"id": 319, "chapter": "CHƯƠNG 3", "question": "Câu 89. Điểm mới nổi bật được Đại hội lần thứ IX của Đảng (2001) đánh giá về kết quả đạt được sau 15 năm thực hiện công cuộc đổi mới là gì?", "options": ["A. Nước ta đã bước đầu củng cố vững chắc được nền kinh tế thị trường định hướng xã hội chủ nghĩa", "B. Nước ta đã ra khỏi khủng hoảng kinh tế – xã hội", "C. Đời sống vật chất và tinh thần của nhân dân ta đã được cải thiện đáng kể", "D. Nước ta đã ra khỏi tình trạng kém phát triển"], "answer": 3, "explanation": "Mốc lịch sử 15 năm đổi mới giúp nước ta bước đầu ra khỏi tình trạng nước nghèo kém phát triển (Trang 126)."},
  {"id": 320, "chapter": "CHƯƠNG 3", "question": "Câu 90. Trọng tâm hàng đầu trong kế hoạch phát triển kinh tế 5 năm (2001-2005) được Đại hội lần thứ IX của Đảng (2001) thông qua là gì?", "options": ["A. Tăng cường củng cố quan hệ sản xuất xã hội chủ nghĩa", "B. Thực hiện CNH-HĐH nông nghiệp, nông thôn", "C. Ổn định tình hình kinh tế – xã hội", "D. Đẩy mạnh thu hút đầu tư nước ngoài"], "answer": 1, "explanation": "Trọng tâm giai đoạn 2001-2005 là đẩy mạnh công nghiệp hóa, hiện đại hóa nông nghiệp và nông thôn (Trang 122)."},
  {"id": 321, "chapter": "CHƯƠNG 3", "question": "Câu 91. Tốc độ tăng trưởng kinh tế của Việt Nam giai đoạn 1996-2000 có xu hướng chậm lại do nguyên nhân khách quan trực tiếp nào tác động?", "options": ["A. Do thiên tai, bão lũ kéo dài liên tiếp trên cả nước", "B. Khủng hoảng tài chính châu Á những năm 1997-1998", "C. Do ảnh hưởng từ cuộc khủng hoảng kinh tế thế giới", "D. Do kinh tế Liên Xô và các nước Đông Âu sụp đổ"], "answer": 1, "explanation": "Nền kinh tế bị ảnh hưởng gián tiếp từ cuộc Khủng hoảng tài chính - tiền tệ châu Á 1997-1998 (Trang 123)."},
  {"id": 322, "chapter": "CHƯƠNG 3", "question": "Câu 92. Chủ trương xây dựng và phát triển nền văn hóa Việt Nam tiên tiến, đậm đà bản sắc dân tộc được thông qua tại Hội nghị Trung ương nào?", "options": ["A. Hội nghị Trung ương 5 khóa VIII (1998)", "B. Hội nghị Trung ương 6 khóa VIII (1999)", "C. Hội nghị Trung ương 2 khóa VIII (1996)", "D. Hội nghị Trung ương 3 khóa VIII (1997)"], "answer": 0, "explanation": "Được thông qua tại Hội nghị Trung ương 5 khóa VIII họp năm 1998 (Trang 124)."},
  {"id": 323, "chapter": "CHƯƠNG 3", "question": "Câu 93. Đại hội nào của Đảng đã xác định: Nền kinh tế thị trường định hướng xã hội chủ nghĩa là mô hình kinh tế tổng quát của nước ta trong thời kỳ quá độ lên chủ nghĩa xã hội?", "options": ["A. Đại hội đại biểu toàn quốc lần thứ VIII của Đảng (1996)", "B. Đại hội đại biểu lần thứ IX (2001)", "C. Đại hội đại biểu toàn quốc lần thứ X của Đảng (2006)", "D. Đại hội đại biểu toàn quốc lần thứ XI của Đảng (2011)"], "answer": 1, "explanation": "Đại hội IX lần đầu xác định kinh tế thị trường định hướng XHCN là mô hình kinh tế tổng quát (Trang 124)."},
  {"id": 324, "chapter": "CHƯƠNG 3", "question": "Câu 94. Hãy điền vào chỗ … trong câu sau: Theo nhận thức của Đảng, kinh tế thị trường định hướng xã hội chủ nghĩa ở Việt Nam: \"...\"", "options": ["A. Là nền kinh tế thị trường tự do, vận hành theo cơ chế tự điều tiết của quy luật cung – cầu", "B. Là nền kinh tế hàng hóa nhiều thành phần vận hành theo cơ chế thị trường có sự quản lý của Nhà nước theo định hướng xã hội chủ nghĩa", "C. Là nền kinh tế kế hoạch hóa tập trung, bao cấp của Nhà nước", "D. Nền kinh tế lấy tự cung, tự cấp làm nền tảng"], "answer": 1, "explanation": "Là nền kinh tế hàng hóa nhiều thành phần vận hành theo cơ chế thị trường dưới sự quản lý của Nhà nước (Trang 124)."},
  {"id": 325, "chapter": "CHƯƠNG 3", "question": "Câu 95. Theo quan điểm của Đảng Cộng sản Việt Nam, thành phần kinh tế nào giữ vai trò chủ đạo trong nền kinh tế thị trường định hướng xã hội chủ nghĩa?", "options": ["A. Kinh tế tập thể", "B. Kinh tế tư nhân", "C. Kinh tế nhà nước", "D. Kinh tế có vốn đầu tư nước ngoài"], "answer": 2, "explanation": "Kinh tế Nhà nước được xác định giữ vai trò chủ đạo, liên kết định hướng phát triển (Trang 124)."},
  {"id": 326, "chapter": "CHƯƠNG 3", "question": "Câu 96. Đại hội đại biểu toàn quốc lần thứ mấy của Đảng đã thông qua nhận định: \"Đảng và Nhà nước ta chủ trương thực hiện nhất quán và lâu dài chính sách phát triển nền kinh tế hàng hóa nhiều thành phần vận hành theo cơ chế thị trường, có sự quản lý của Nhà nước theo định hướng xã hội chủ nghĩa\"?", "options": ["A. Đại hội đại biểu toàn quốc lần thứ VIII của Đảng (1996)", "B. Đại hội đại biểu toàn quốc lần thứ IX của Đảng (2001)", "C. Đại hội đại biểu toàn quốc lần thứ X của Đảng (2006)", "D. Đại hội đại biểu toàn quốc lần thứ XI của Đảng (2011)"], "answer": 1, "explanation": "Chính sách phát triển lâu dài nền kinh tế nhiều thành phần được tái khẳng định rõ nét ở Đại hội IX (Trang 125)."},
  {"id": 327, "chapter": "CHƯƠNG 3", "question": "Câu 97. Người được bầu làm Tổng Bí thư tại Đại hội lần thứ IX và lần thứ X của Đảng là ai?", "options": ["A. Đ/c Đỗ Mười", "B. Đ/c Nông Đức Mạnh", "C. Đ/c Lê Khả Phiêu", "D. Đ/c Nguyễn Phú Trọng"], "answer": 1, "explanation": "Đồng chí Nông Đức Mạnh được bầu làm Tổng Bí thư tại Đại hội IX (2001) và tái đắc cử tại Đại hội X (2006) (Trang 125)."},
  {"id": 328, "chapter": "CHƯƠNG 3", "question": "Câu 98. Điểm mới trong nhận thức về phát triển kinh tế tư nhân tại Đại hội lần thứ X của Đảng (2006) là gì?", "options": ["A. Khuyến khích sự phát triển của kinh tế tư nhân trên mọi ngành nghề", "B. Hạn chế tối đa sự phát triển của kinh tế tư nhân trong các ngành kinh tế then chốt", "C. Thừa nhận sự phát triển của kinh tế tư nhân và cho phép đảng viên làm kinh tế tư nhân", "D. Cho phép đảng viên làm kinh tế tư nhân không giới hạn về quy mô sản xuất"], "answer": 2, "explanation": "Đại hội X cho phép đảng viên làm kinh tế tư nhân – bước đột phá lớn trong tư duy lý luận (Trang 125)."},
  {"id": 329, "chapter": "CHƯƠNG 3", "question": "Câu 99. Sự kiện đối ngoại nổi bật đánh dấu quá trình hội nhập quốc tế của Việt Nam bước lên tầm cao mới vào cuối năm 2006 là?", "options": ["A. Việt Nam gia nhập Hiệp hội các nước Đông Nam Á (ASEAN)", "B. Việt Nam ký Hiệp định thương mại tự do với Hoa Kỳ", "C. Việt Nam bình thường hóa quan hệ với Hoa Kỳ", "D. Việt Nam gia nhập Tổ chức Thương mại Thế giới (WTO)"], "answer": 3, "explanation": "Tháng 11/2006, Việt Nam chính thức trở thành thành viên thứ 150 của Tổ chức Thương mại Thế giới WTO (Trang 125)."},
  {"id": 330, "chapter": "CHƯƠNG 3", "question": "Câu 100. Ngày 28/7/1995 ghi dấu ấn sự kiện đối ngoại quan trọng nào của Việt Nam?", "options": ["A. Việt Nam gia nhập Tổ chức Thương mại thế giới (WTO)", "B. Việt Nam gia nhập Hiệp hội các nước Đông Nam Á (ASEAN)", "C. Việt Nam bình thường hóa quan hệ ngoại giao với Mỹ", "D. Việt Nam và Mỹ ký kết Hiệp định Thương mại Việt – Mỹ"], "answer": 1, "explanation": "Ngày 28/7/1995, Việt Nam chính thức gia nhập và trở thành thành viên thứ 7 của ASEAN (Trang 119)."},
  {"id": 331, "chapter": "CHƯƠNG 3", "question": "Câu 101. Ngày 11/7/1995 ghi dấu ấn sự kiện đối ngoại quan trọng nào của Việt Nam?", "options": ["A. Việt Nam gia nhập Tổ chức Thương mại thế giới (WTO)", "B. Việt Nam gia nhập Hiệp hội các nước Đông Nam Á (ASEAN)", "C. Tổng thống Mỹ Bill Clinton tuyên bố bình thường hóa quan hệ ngoại giao với Việt Nam", "D. Việt Nam và Mỹ ký kết Hiệp định Thương mại Việt – Mỹ"], "answer": 2, "explanation": "Ngày 11/7/1995, Việt Nam và Hoa Kỳ chính thức bình thường hóa quan hệ ngoại giao song phương (Trang 119)."},
  {"id": 332, "chapter": "CHƯƠNG 3", "question": "Câu 102. Hai sự kiện đối ngoại nổi bật diễn ra vào tháng 7 năm 1995 đánh dấu bước đột phá mở rộng quan hệ đối ngoại của Việt Nam là?", "options": ["A. Bình thường hóa quan hệ ngoại giao với Mỹ và gia nhập Tổ chức Hiệp hội các nước Đông Nam Á (ASEAN)", "B. Bình thường hóa với Mỹ và ký Hiệp định thương mại song phương Việt – Mỹ", "C. Bình thường hóa quan hệ với Trung Quốc và gia nhập ASEAN", "D. Gia nhập ASEAN và bình thường hóa quan hệ với Trung Quốc"], "answer": 0, "explanation": "Sự kiện bình thường hóa quan hệ với Mỹ và gia nhập ASEAN mở ra chương mới trong hội nhập quốc tế (Trang 119)."},
  {"id": 333, "chapter": "CHƯƠNG 3", "question": "Câu 103. Bản Cương lĩnh xây dựng đất nước trong thời kỳ quá độ lên chủ nghĩa xã hội (Bổ sung, phát triển năm 2011) được thông qua tại Đại hội nào?", "options": ["A. Đại hội đại biểu toàn quốc lần thứ X của Đảng (2006)", "B. Đại hội đại biểu toàn quốc lần thứ XI của Đảng (2011)", "C. Đại hội đại biểu toàn quốc lần thứ XII của Đảng (2016)", "D. Đại hội đại biểu toàn quốc lần thứ XIII của Đảng (2021)"], "answer": 1, "explanation": "Cương lĩnh bổ sung, phát triển năm 2011 (Cương lĩnh 2011) được thông qua tại Đại hội XI của Đảng (Trang 126)."},
  {"id": 334, "chapter": "CHƯƠNG 3", "question": "Câu 104. Sách lược đối ngoại nổi bật của Đảng trước những biến động phức tạp của tình hình Biển Đông trong giai đoạn 2011-2015 là:", "options": ["A. Bình thường hóa quan hệ với Trung Quốc", "B. Khẳng định chủ quyền không thể tranh chấp của Việt Nam đối với hai quần đảo Hoàng Sa và Trường Sa", "C. Đưa vấn đề tranh chấp Biển Đông ra Liên hợp quốc giải quyết", "D. Thực hiện chính sách đối ngoại quốc phòng \"3 không\""], "answer": 1, "explanation": "Chủ trương nhất quán là kiên quyết bảo vệ và khẳng định chủ quyền không thể chối cãi với Hoàng Sa và Trường Sa (Trang 126)."},
  {"id": 335, "chapter": "CHƯƠNG 3", "question": "Câu 105. Đồng chí Nguyễn Phú Trọng được bầu làm Tổng Bí thư Ban Chấp hành Trung ương Đảng lần đầu tiên vào Đại hội nào?", "options": ["A. Đại hội đại biểu lần thứ IX (2001)", "B. Đại hội đại biểu lần thứ X (2006)", "C. Đại hội đại biểu lần thứ XI (2011)", "D. Đại hội đại biểu lần thứ XII (2016)"], "answer": 2, "explanation": "Đồng chí Nguyễn Phú Trọng được bầu làm Tổng Bí thư tại Đại hội đại biểu lần thứ XI vào năm 2011 (Trang 126)."},
  {"id": 336, "chapter": "CHƯƠNG 3", "question": "Câu 106. Đại hội đại biểu toàn quốc lần thứ mấy của Đảng đã đề ra mục tiêu: Đến giữa thế kỷ XXI, nước ta trở thành nước phát triển, theo định hướng xã hội chủ nghĩa?", "options": ["A. Đại hội đại biểu toàn quốc lần thứ X (2006)", "B. Đại hội đại biểu toàn quốc lần thứ XI (2011)", "C. Đại hội đại biểu toàn quốc lần thứ XII (2016)", "D. Đại hội đại biểu toàn quốc lần thứ XIII (2021)"], "answer": 3, "explanation": "Đại hội XIII (2021) đề ra tầm nhìn phát triển đất nước đến năm 2030 và giữa thế kỷ XXI (Trang 129)."},
  {"id": 337, "chapter": "CHƯƠNG 3", "question": "Câu 107. Trong các bài học kinh nghiệm phát triển đất nước được rút ra tại Đại hội lần thứ XIII của Đảng (2021), bài học nào phản ánh động lực chính của công cuộc đổi mới?", "options": ["A. Lấy dân làm gốc, nhân dân là chủ thể của công cuộc đổi mới, xây dựng và bảo vệ Tổ quốc", "B. Sự lãnh đạo đúng đắn, sáng tạo của Đảng", "C. Đổi mới phải chủ động, sáng tạo, đi đôi với ổn định chính trị", "D. Kết hợp sức mạnh dân tộc với sức mạnh thời đại"], "answer": 0, "explanation": "Đại hội XIII nhấn mạnh bài học \"Lấy dân làm gốc\", coi nhân dân là chủ thể quyết định mọi thắng lợi (Trang 131)."},
  {"id": 338, "chapter": "CHƯƠNG 3", "question": "Câu 108. Trong các bài học kinh nghiệm phát triển đất nước được rút ra tại Đại hội lần thứ XIII của Đảng (2021), bài học nào phản ánh nhân tố quyết định hàng đầu thắng lợi của cách mạng?", "options": ["A. Sự kiên định và vận dụng sáng tạo chủ nghĩa Mác – Lênin, tư tưởng Hồ Chí Minh", "B. Sự lãnh đạo đúng đắn, sáng tạo của Đảng", "C. Sức mạnh của khối đại đoàn kết toàn dân tộc", "D. Kết hợp sức mạnh dân tộc với sức mạnh thời đại"], "answer": 0, "explanation": "Kiên định, vận dụng và phát triển sáng tạo chủ nghĩa Mác - Lênin, tư tưởng Hồ Chí Minh là nhân tố quyết định hàng đầu (Trang 130)."},
  {"id": 339, "chapter": "CHƯƠNG 3", "question": "Câu 109. Trong các bài học kinh nghiệm phát triển đất nước được rút ra tại Đại hội lần thứ XIII của Đảng (2021), bài học nào phản ánh mối quan hệ giữa Đảng và nhân dân?", "options": ["A. Xây dựng Đảng và hệ thống chính trị trong sạch, vững mạnh", "B. Lấy dân làm gốc, nhân dân là chủ thể của công cuộc đổi mới", "C. Có sự kết hợp chặt chẽ, hiệu quả công tác củng cố vai trò lãnh đạo của Đảng và niềm tin của nhân dân", "D. Nêu cao tinh thần tự phê bình và phê bình"], "answer": 2, "explanation": "Đảng củng cố vai trò lãnh đạo bằng việc củng cố niềm tin và sự ủng hộ thiết thực của nhân dân (Trang 131)."},
  {"id": 340, "chapter": "CHƯƠNG 3", "question": "Câu 110. Nhiệm vụ trọng tâm hàng đầu được Đại hội lần thứ XIII của Đảng (2021) xác định là gì?", "options": ["A. Phát triển kinh tế – xã hội nhanh và bền vững", "B. Xây dựng Đảng và hệ thống chính trị trong sạch, vững mạnh", "C. Bảo đảm vững chắc quốc phòng và an ninh quốc gia", "D. Chủ động và tích cực hội nhập quốc tế toàn diện, sâu rộng"], "answer": 1, "explanation": "Nhiệm vụ then chốt, hàng đầu là xây dựng Đảng và hệ thống chính trị trong sạch, vững mạnh (Trang 130)."},
  {"id": 341, "chapter": "CHƯƠNG 3", "question": "Câu 111. Đại hội đại biểu toàn quốc lần thứ mấy của Đảng đề ra mục tiêu: Đến năm 2025, nước ta là nước đang phát triển, có công nghiệp theo hướng hiện đại, vượt qua mức thu nhập trung bình thấp?", "options": ["A. Đại hội đại biểu toàn quốc lần thứ XI (2011)", "B. Đại hội đại biểu toàn quốc lần thứ XII (2016)", "C. Đại hội đại biểu toàn quốc lần thứ XIII (2021)", "D. Đại hội đại biểu toàn quốc lần thứ XIV (2026)"], "answer": 2, "explanation": "Mục tiêu cụ thể đến năm 2025 được xác định tại Văn kiện Đại hội đại biểu toàn quốc lần thứ XIII (Trang 132)."},
  {"id": 342, "chapter": "CHƯƠNG 3", "question": "Câu 112. Tầm nhìn chiến lược phát triển đất nước đến năm 2030 và năm 2045 được thông qua tại Đại hội nào của Đảng?", "options": ["A. Đại hội đại biểu toàn quốc lần thứ XI (2011)", "B. Đại hội đại biểu toàn quốc lần thứ XII (2016)", "C. Đại hội đại biểu toàn quốc lần thứ XIII (2021)", "D. Đại hội đại biểu toàn quốc lần thứ XIV (2026)"], "answer": 2, "explanation": "Đại hội XIII (2021) đã đề ra tầm nhìn đến năm 2030 (100 năm thành lập Đảng) và 2045 (100 năm lập nước) (Trang 130)."},
  {"id": 343, "chapter": "CHƯƠNG 3", "question": "Câu 113. Tổng kết 35 năm thực hiện công cuộc đổi mới (1986-2021), Đại hội lần thứ XIII của Đảng (2021) rút ra nhận định lịch sử nào dưới đây?", "options": ["A. Đất nước đã đạt được những thành tựu to lớn, có ý nghĩa lịch sử", "B. Vị thế và uy tín quốc tế của nước ta ngày càng được nâng cao", "C. Sự nghiệp đổi mới của Đảng là đúng đắn, sáng tạo, con đường đi lên chủ nghĩa xã hội của Việt Nam là phù hợp với thực tiễn Việt Nam và xu thế phát triển của thời đại", "D. Nước ta đã ra khỏi tình trạng kém phát triển, bước vào thời kỳ đẩy mạnh công nghiệp hóa"], "answer": 2, "explanation": "Khẳng định đường lối đổi mới của Đảng là hoàn toàn đúng đắn, con đường đi lên CNXH là phù hợp thực tế (Trang 132)."},
  {"id": 344, "chapter": "CHƯƠNG 3", "question": "Câu 114. Bài học kinh nghiệm đầu tiên được rút ra tại Đại hội lần thứ XIII của Đảng (2021) nhấn mạnh công tác nào?", "options": ["A. Phát triển kinh tế – xã hội", "B. Xây dựng Đảng Cộng sản Việt Nam vững mạnh", "C. Củng cố khối đại đoàn kết toàn dân tộc", "D. Kết hợp sức mạnh dân tộc với sức mạnh thời đại"], "answer": 1, "explanation": "Bài học thứ nhất đặt trọng tâm vào xây dựng, chỉnh đốn Đảng và hệ thống chính trị trong sạch, vững mạnh (Trang 130)."},
  {"id": 345, "chapter": "CHƯƠNG 3", "question": "Câu 115. Trong các bài học kinh nghiệm phát triển đất nước được rút ra tại Đại hội lần thứ XIII của Đảng (2021), nội dung nào nói về phương thức lãnh đạo của Đảng?", "options": ["A. Đảng phải luôn bám sát thực tiễn để kịp thời điều chỉnh chính sách", "B. Đảng phải luôn coi trọng đổi mới phương thức lãnh đạo, nâng cao năng lực lãnh đạo và sức chiến đấu của Đảng", "C. Đảng phải thực hiện tốt nguyên tắc tập trung dân chủ", "D. Đảng phải tăng cường liên hệ mật thiết với nhân dân"], "answer": 1, "explanation": "Bài học nhấn mạnh Đảng phải thường xuyên đổi mới phương thức và nâng cao năng lực lãnh đạo (Trang 131)."},
  {"id": 346, "chapter": "CHƯƠNG 3", "question": "Câu 116. Trong các bài học kinh nghiệm phát triển đất nước được rút ra tại Đại hội lần thứ XIII của Đảng (2021), nội dung nào nói về vai trò của khối đại đoàn kết toàn dân tộc?", "options": ["A. Đại đoàn kết toàn dân tộc là động lực chủ yếu của sự nghiệp", "B. Phát huy tối đa sức mạnh nội lực, củng cố và tăng cường khối đại đoàn kết toàn dân tộc", "C. Đại đoàn kết toàn dân tộc là nhân tố quyết định thắng lợi", "D. Đoàn kết toàn dân tộc trên nền tảng liên minh công – nông – trí thức"], "answer": 1, "explanation": "Khẳng định bài học khơi dậy tinh thần yêu nước, khát vọng phát triển và sức mạnh đại đoàn kết toàn dân tộc (Trang 131)."},
  {"id": 347, "chapter": "CHƯƠNG 3", "question": "Câu 117. Trong các bài học kinh nghiệm phát triển đất nước được rút ra tại Đại hội lần thứ XIII của Đảng (2021), nội dung nào nói về mối quan hệ giữa Đảng và nhân dân?", "options": ["A. Đảng lãnh đạo, Nhà nước quản lý, nhân dân làm chủ", "B. Trong mọi công việc của Đảng và Nhà nước, phải luôn quán triệt sâu sắc quan điểm 'dân là gốc'", "C. Đảng phải chịu sự giám sát của nhân dân", "D. Đảng phải dựa vào nhân dân để xây dựng Đảng"], "answer": 1, "explanation": "Trong mọi công việc luôn quán triệt quan điểm \"dân là gốc\", thật sự tin dân, trọng dân, phục vụ dân (Trang 131)."},
  {"id": 348, "chapter": "CHƯƠNG 3", "question": "Câu 118. Nhận định lịch sử: \"Đất nước ta chưa bao giờ có được cơ đồ, tiềm lực, vị thế và uy tín quốc tế như ngày nay\" được nêu ra ở văn kiện nào dưới đây?", "options": ["A. Cương lĩnh xây dựng đất nước trong thời kỳ quá độ (Bổ sung, phát triển năm 2011)", "B. Nghị quyết Đại hội đại biểu toàn quốc lần thứ XII của Đảng (2016)", "C. Nghị quyết Đại hội đại biểu toàn quốc lần thứ XIII của Đảng (2021)", "D. Báo cáo chính trị tại Đại hội đại biểu lần thứ XIII của Đảng (2021)"], "answer": 2, "explanation": "Nhận định mang tính tổng quát lịch sử được đưa vào Nghị quyết Đại hội đại biểu toàn quốc lần thứ XIII (Trang 132)."},
  {"id": 349, "chapter": "CHƯƠNG 3", "question": "Câu 119. Bài học kinh nghiệm đầu tiên được rút ra tại Đại hội lần thứ XIII của Đảng (2021) nhấn mạnh công tác nào?", "options": ["A. Phát triển kinh tế – xã hội", "B. Xây dựng Đảng Cộng sản Việt Nam vững mạnh", "C. Củng cố khối đại đoàn kết toàn dân tộc", "D. Kết hợp sức mạnh dân tộc với sức mạnh thời đại"], "answer": 1, "explanation": "Bài học đầu tiên là xây dựng chỉnh đốn Đảng toàn diện cả về chính trị, tư tưởng, tổ chức và đạo đức (Trang 130)."},
  {"id": 350, "chapter": "CHƯƠNG 3", "question": "Câu 120. Báo cáo chính trị tại Đại hội lần thứ XIII của Đảng (2021) đã xác định nước ta có mấy bài học kinh nghiệm lịch sử?", "options": ["A. 3 bài học", "B. 4 bài học", "C. 5 bài học", "D. 6 bài học"], "answer": 2, "explanation": "Đại hội XIII đúc kết 5 bài học kinh nghiệm quý báu qua thực tiễn đổi mới phát triển đất nước (Trang 128)."},
  {"id": 351, "chapter": "CHƯƠNG 3", "question": "Câu 121. Ban Chấp hành Trung ương Đảng họp Hội nghị lần thứ 4 khóa XIII (10/2021) đã ra kết luận về công tác nào dưới đây?", "options": ["A. Phát triển kinh tế – xã hội nhanh và bền vững", "B. Bảo đảm vững chắc quốc phòng và an ninh quốc gia", "C. Xây dựng, chỉnh đốn Đảng và hệ thống chính trị trong sạch, vững mạnh toàn diện", "D. Đẩy mạnh cải cách hành chính"], "answer": 2, "explanation": "Hội nghị Trung ương 4 khóa XIII tập trung ra Kết luận về xây dựng, chỉnh đốn Đảng và hệ thống chính trị (Trang 128)."},
  {"id": 352, "chapter": "CHƯƠNG 3", "question": "Câu 122. Công cuộc đổi mới toàn diện đất nước ở nước ta bắt đầu từ năm nào?", "options": ["A. 1975", "B. 1976", "C. 1986", "D. 1991"], "answer": 2, "explanation": "Bắt đầu từ dấu mốc lịch sử Đại hội đại biểu toàn quốc lần thứ VI họp tháng 12/1986 (Trang 110)."},
  {"id": 353, "chapter": "CHƯƠNG 3", "question": "Câu 123. Dưới góc độ lý luận cách mạng, lực lượng nào khởi xướng và lãnh đạo công cuộc đổi mới toàn diện đất nước?", "options": ["A. Nhân dân Việt Nam", "B. Giai cấp công nhân và nông dân Việt Nam", "C. Nhà nước xã hội chủ nghĩa Việt Nam", "D. Đảng Cộng sản Việt Nam"], "answer": 3, "explanation": "Đảng Cộng sản Việt Nam là lực lượng duy nhất khởi xướng, dẫn dắt và lãnh đạo công cuộc đổi mới (Trang 132)."},
  {"id": 354, "chapter": "CHƯƠNG 3", "question": "Câu 124. Mục tiêu bao trùm xuyên suốt của sự nghiệp đổi mới ở Việt Nam là gì?", "options": ["A. Đưa nước ta trở thành nước phát triển có thu nhập cao", "B. Thực hiện thắng lợi kế hoạch phát triển kinh tế – xã hội", "C. Xây dựng thành công chủ nghĩa xã hội và bảo vệ vững chắc Tổ quốc Việt Nam xã hội chủ nghĩa", "D. Phát huy quyền làm chủ của nhân dân"], "answer": 2, "explanation": "Mục tiêu bao trùm là xây dựng thành công CNXH và bảo vệ vững chắc Tổ quốc Việt Nam xã hội chủ nghĩa (Trang 132)."},
  {"id": 355, "chapter": "CHƯƠNG 3", "question": "Câu 125. Một trong những thành tựu đối ngoại nổi bật của Việt Nam sau hơn 35 năm đổi mới là?", "options": ["A. Việt Nam thiết lập quan hệ đối tác chiến lược toàn diện với tất cả các quốc gia trên thế giới", "B. Vị thế và uy tín quốc tế của Việt Nam ngày càng được nâng cao", "C. Việt Nam là thành viên của tất cả các tổ chức quốc tế lớn", "D. Việt Nam đã giải quyết triệt để mọi tranh chấp về biên giới, lãnh hải"], "answer": 1, "explanation": "Hơn 35 năm đổi mới đã giúp nâng cao rõ rệt vị thế, uy tín ngoại giao của Việt Nam trên trường quốc tế (Trang 132)."},
  {"id": 356, "chapter": "CHƯƠNG 3", "question": "Câu 126. Thành tựu vĩ đại có ý nghĩa lịch sử của Việt Nam sau hơn 35 năm đổi mới là do nhân tố quyết định nào?", "options": ["A. Sự giúp đỡ to lớn của bạn bè quốc tế", "B. Sự nỗ lực vượt bậc của toàn thể nhân dân Việt Nam", "C. Sự lãnh đạo đúng đắn, sáng tạo của Đảng", "D. Các điều kiện tự nhiên, tài nguyên phong phú của đất nước"], "answer": 2, "explanation": "Sự lãnh đạo đúng đắn, sáng tạo của Đảng Cộng sản Việt Nam là nhân tố quyết định hàng đầu (Trang 132)."},
  {"id": 357, "chapter": "CHƯƠNG 3", "question": "Câu 127. Đảng Cộng sản Việt Nam xác định mục tiêu tổng quát của sự nghiệp đổi mới là xây dựng đất nước Việt Nam:", "options": ["A. Dân giàu, nước mạnh, xã hội dân chủ, công bằng, văn minh", "B. Dân giàu, nước mạnh, dân chủ, công bằng, văn minh", "C. Dân giàu, nước mạnh, công bằng, dân chủ, văn minh", "D. Dân giàu, nước mạnh, công bằng, văn minh"], "answer": 1, "explanation": "Mục tiêu tổng quát được đúc kết ngắn gọn: \"Dân giàu, nước mạnh, dân chủ, công bằng, văn minh\" (Trang 132)."},
  {"id": 358, "chapter": "CHƯƠNG 3", "question": "Câu 128. Để giữ vững định hướng xã hội chủ nghĩa trong quá trình đổi mới, Đảng Cộng sản Việt Nam luôn kiên định nội dung nào?", "options": ["A. Kiên định mục tiêu độc lập dân tộc và chủ nghĩa xã hội", "B. Kiên định mô hình kinh tế kế hoạch hóa tập trung", "C. Kiên định nguyên tắc không nhận đầu tư nước ngoài", "D. Kiên định mô hình phát triển kinh tế hướng nội"], "answer": 0, "explanation": "Yêu cầu bất di bất dịch là kiên định mục tiêu độc lập dân tộc gắn liền với chủ nghĩa xã hội (Trang 130)."},
  {"id": 359, "chapter": "CHƯƠNG 3", "question": "Câu 129. Một trong những quan điểm chỉ đạo đổi mới của Đảng Cộng sản Việt Nam là:", "options": ["A. Tập trung phát triển kinh tế nhanh bằng mọi giá", "B. Không ngừng nâng cao đời sống vật chất và tinh thần của nhân dân", "C. Hạn chế tối đa sự tham gia của các thành phần kinh tế tư nhân", "D. Giữ nguyên mô hình tổ chức hệ thống chính trị kiểu cũ"], "answer": 1, "explanation": "Quan điểm chỉ đạo nhất quán là đổi mới vì nhân dân, không ngừng nâng cao đời sống vật chất, tinh thần cho dân (Trang 131)."}
];
